import{_ as a,o as l,c as p,a5 as s}from"./chunks/framework.B5tqjWbr.js";const _=JSON.parse('{"title":"教程 0023：单相 UPS 旁路同步与切换许可","description":"","frontmatter":{"title":"教程 0023：单相 UPS 旁路同步与切换许可","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0023-single-phase-bypass-sync-transfer.html","status":"learning","visibility":"public","summary":"Imported from 0023-single-phase-bypass-sync-transfer.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0023-single-phase-bypass-sync-transfer.md","filePath":"content/power/lessons/0023-single-phase-bypass-sync-transfer.md","lastUpdated":null}'),i={name:"content/power/lessons/0023-single-phase-bypass-sync-transfer.md"};function n(o,e,t,r,c,d){return l(),p("div",null,[...e[0]||(e[0]=[s(`<h1 id="教程-0023-单相-ups-旁路同步与切换许可" tabindex="-1">教程 0023：单相 UPS 旁路同步与切换许可 <a class="header-anchor" href="#教程-0023-单相-ups-旁路同步与切换许可" aria-label="Permalink to &quot;教程 0023：单相 UPS 旁路同步与切换许可&quot;">​</a></h1><p>中文主讲。一个概念：旁路切换不是看到 PLL 锁定就动作，而是电压、频率、相位都进入窗口并保持一段时间后，状态机才允许切换。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学脚本和教学参数，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>旁路同步（bypass synchronization）是判断逆变器输出与旁路电源是否足够接近。旁路切换（bypass transfer）是把负载从逆变器供电路径切到旁路路径，或从旁路切回逆变器路径。</p><p>本节只讲一个概念：电压幅值、频率、相位三项都满足窗口，并持续满足保持时间（hold time）后，状态机（state machine）才允许切换。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）在逆变器故障、过载、维修旁路或模式切换时可能使用旁路。如果不同步就切换，负载会看到电压突变，静态开关或继电器也可能承受冲击。</p><p>锁相环（phase-locked loop / PLL）能给出旁路或电网相位，但 PLL 锁定不等于马上能切换。固件还要检查均方根（root mean square / RMS）电压、频率差和相位误差（phase error）。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>两个人交接一个正在转动的方向盘时，手的位置、速度和力度都要接近。旁路切换也类似：电压幅值像力度，频率像速度，相位像手的位置。只满足其中一个条件不够。</p><pre><code>RMS 电压
幅值窗口

频率差
速度窗口

相位误差
位置窗口

保持时间
连续满足
才给许可

切换许可
0 / 1

任意一个条件失效，许可撤销；相位跳变后必须重新等待。
</code></pre><p>图 1：旁路切换许可是多条件窗口加保持时间，不是单个 PLL 标志。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>voltage_ok = abs(V_bypass - V_inv) / V_inv = hold_time</p><p>默认教学参数：</p><p>V_inv = 220 Vrms voltage window = 10 % frequency window = 0.20 Hz phase window = 5 deg hold time = 30 ms</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\single_phase_bypass_sync_transfer.py</p><p>脚本会生成并默认尝试自动打开图片；如果打不开，会打印完整路径。</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/single_phase_bypass_sync_transfer.png</code></p><p>对比任务 python simulations\\python\\single_phase_bypass_sync_transfer.py --phase-window-deg 2 --output simulations\\results\\bypass_sync_phase_2deg.png python simulations\\python\\single_phase_bypass_sync_transfer.py --sync-hold-time 0.060 --output simulations\\results\\bypass_sync_hold_60ms.png</p></li></ul><p>观察相位窗口变窄、保持时间变长后，切换许可出现时间如何变化。</p><p>仿真观察顺序：</p><ul><li><p>先看 RMS 电压是否进入电压窗口。</p></li><li><p>再看频率差是否进入频率窗口。</p></li><li><p>再看相位误差是否进入相位窗口。</p></li><li><p>最后看 <code>All sync windows OK</code> 和 <code>Transfer allowed</code> 之间是否相差保持时间。</p></li><li><p>观察 200 ms 相位跳变后，切换许可是否撤销。</p></li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 C 工程里，旁路同步常分散在多个模块：</p><ul><li><p><code>pll.c</code>：提供旁路或电网相位。</p></li><li><p><code>rms.c</code>：计算逆变器和旁路 RMS 电压。</p></li><li><p><code>sync_check.c</code>：判断电压、频率、相位窗口和保持时间。</p></li><li><p><code>state_machine.c</code>：决定是否从逆变模式进入旁路模式。</p></li><li><p><code>protection.c</code>：相位跳变、旁路异常、逆变器故障时撤销许可或锁存故障。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**PLL locked 就等于可以切旁路。 **纠正：**还要检查 RMS 电压、频率差、相位差和保持时间。</p></li><li><p>**误解：**相位刚好落入窗口的一瞬间就能切。 **纠正：**要连续保持一段时间，避免噪声或瞬时交叉造成误许可。</p></li><li><p>**误解：**旁路切换只是继电器动作。 **纠正：**动作前的软件许可、保护锁存、静态开关时序和状态机条件都很关键。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能解释旁路同步和旁路切换的区别。</p></li><li><p>能根据图指出哪个条件最晚进入窗口。</p></li><li><p>能解释为什么需要保持时间。</p></li><li><p>能说明相位跳变后为什么要撤销切换许可。</p></li><li><p>能基于图中参数准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>默认仿真中，三项同步窗口分别是什么？</p></li><li><p><code>All sync windows OK</code> 第一次变为 1 后，为什么 <code>Transfer allowed</code> 不是立刻变为 1？</p></li><li><p>200 ms 相位跳变后，哪条曲线先变化？状态机应该如何处理这个事件？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>single_phase_bypass_sync_transfer.py</code> 看到三项窗口都满足并保持 30 ms 后才允许切换。公司工程里旁路切换许可通常有哪些窗口阈值？</p></li><li><p>我在图中看到 200 ms 相位跳变后 <code>Transfer allowed</code> 立刻撤销。真实产品里相位异常后是否还会加入额外延时或故障锁存？</p></li><li><p>公司代码里旁路同步判断是在 PLL 模块、状态机模块，还是单独的同步检查模块中实现？</p></li></ul><p>**下一步：**这节把 PLL、逆变器状态机和 UPS 系统切换连接起来。后续可以继续做三电平逆变器或 Vienna 整流器，但旁路同步是读 UPS 系统代码前必须会看的接口。</p><p>关联：<a href="./0017-single-phase-pll-lock-detector.html">PLL 锁定检测</a>；<a href="./0021-single-phase-inverter-fault-state-machine.html">逆变器故障状态机</a>；源稿：<code>concepts/control/single-phase-bypass-sync-transfer.md</code>。</p><pre><code>上一节：教程 0022：UPS 固件实时调度骨架
下一节：教程 0024：UPS 模式状态机
</code></pre>`,42)])])}const u=a(i,[["render",n]]);export{_ as __pageData,u as default};
